sql:
SELECT COUNT(*) AS successful_encounters
FROM raid_encounter_logs
WHERE instance_id = 1 AND success = 1;

SELECT instance_name
FROM raid_instances
WHERE instance_id = 1;

SELECT COUNT(player_id)
FROM guild_members
WHERE guild_id = 0;

SELECT AVG(success) AS average_successful_encounters
FROM raid_encounter_logs
WHERE instance_id = 1;

SELECT COUNT(player_id) AS total_players
FROM guild_members
WHERE guild_id = (SELECT guild_id FROM guilds WHERE guild_name = 'Another Guild');

SELECT difficulty_name
FROM difficulties
WHERE version > 1;

external_knowledge:
- "dungeons" refers to raid instances;
- "challenges within them" refers to difficulty levels available for the raid instance;
- "sailed above the halfway mark in terms of their overall performance score" means the average statistic value is greater than 50.

- 'fiery challenges of the Molten Core' refers to the raid instance named 'Molten Core';
- 'realm of Normal difficulty' signifies the difficulty level named 'Normal';
- 'average score' implies the average of the statistic values, which typically represents ratings or performance metrics in this context.
